import React from "react"

interface QuoteInterface {
  quote: string
  name: string
  source?: string | null
  className?: string
}

/**
 * Blockquote component
 * @param props <QuoteInterface> Specifies the quote, and author (source / className are optional)
 */
const Quote: React.FunctionComponent<QuoteInterface> = props => {
  return (
    <blockquote
      className={
        "my-4 relative p-4 text-xl sm:text-lg  italic border-l-4 quote " +
        (props.className || "")
      }
    >
      <p className="mb-4 font-serif">
        <span className="mr-2 font-serif text-xl md:text-3xl lg:text-5xl text-gray-100 text-opacity-50">
          &ldquo;
        </span>
        {props.quote}
        <span className="ml-2 font-serif text-xl md:text-3xl lg:text-5xl text-gray-100 text-opacity-50">
          &rdquo;
        </span>
      </p>
      <cite>
        <div className="text-right mb-1 text-sm italic">
          - <span className="font-bold">{props.name}</span>
          {props.source && <span>&nbsp;| {props.source}</span>}
        </div>
      </cite>
    </blockquote>
  )
}

export default Quote
